import React, { useState } from "react";
import EditorialFlow from "./EditorialFlow";

interface MediaLibraryProps {
  onBack?: () => void;
}

const MediaLibrary: React.FC<MediaLibraryProps> = ({ onBack }) => {
  const [view, setView] = useState<'library' | 'flow'>('library');
  
  // ✅ ÉTATS POUR LA MODALE D'EXPORTATION
  const [exportModalOpen, setExportModalOpen] = useState(false);
  const [exportFormat, setExportFormat] = useState<'json' | 'csv' | 'pdf'>('json');
  const [exportType, setExportType] = useState<'all' | 'raw' | 'transcribed' | 'book' | 'proofreading1' | 'proofreading2'>('all');
  const [isExporting, setIsExporting] = useState(false);

  // ... (reste du code existant)

  // ✅ FONCTION D'EXPORTATION
  const handleExport = async () => {
    setIsExporting(true);
    
    // Simulation d'export (à remplacer par la vraie logique plus tard)
    await new Promise(resolve => setTimeout(resolve, 1500));
    
    const exportData = {
      exportType,
      exportFormat,
      exportedAt: new Date().toISOString(),
      files: [] // Données réelles à venir
    };
    
    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `bcm-gest-export-${exportType}-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    
    setIsExporting(false);
    setExportModalOpen(false);
    alert('✅ Export réussi !');
  };

  return (
    <div className="container mx-auto px-4 py-4 h-full flex flex-col">
      {/* ... (code existant) */}

      {/* Bouton Exporter dans la barre d'outils */}
      <button
        onClick={() => setExportModalOpen(true)}
        className="px-6 py-3 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 text-white rounded-xl transition-all duration-200 flex items-center gap-2 shadow-lg hover:shadow-xl transform hover:-translate-y-0.5"
      >
        <i className="fas fa-download"></i>
        Exporter
      </button>

      {/* ... (reste du code) */}

      {/* ✅ MODALE D'EXPORTATION */}
      {exportModalOpen && (
        <>
          {/* Overlay */}
          <div
            className="fixed inset-0 bg-black bg-opacity-50 z-50 animate-fade-in backdrop-blur-sm"
            onClick={() => setExportModalOpen(false)}
          ></div>
          
          {/* Modale */}
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 animate-scale-in">
            <div
              className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl max-w-lg w-full overflow-hidden animate-slide-up"
              onClick={(e) => e.stopPropagation()}
            >
              {/* En-tête */}
              <div className="bg-gradient-to-r from-indigo-600 to-purple-600 px-6 py-4">
                <div className="flex justify-between items-center">
                  <h3 className="text-xl font-bold text-white flex items-center gap-2">
                    <i className="fas fa-download"></i>
                    Exporter les données
                  </h3>
                  <button
                    onClick={() => setExportModalOpen(false)}
                    className="text-white/80 hover:text-white transition-colors"
                  >
                    <i className="fas fa-times text-xl"></i>
                  </button>
                </div>
                <p className="text-indigo-100 text-sm mt-1">
                  Choisissez le type de fichiers à exporter
                </p>
              </div>

              {/* Corps */}
              <div className="p-6 space-y-6">
                {/* Type d'export */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-3">
                    📁 Type de fichiers
                  </label>
                  <div className="grid grid-cols-2 gap-3">
                    <ExportOptionCard
                      icon="fa-folder"
                      color="bg-blue-500"
                      label="Fichiers bruts"
                      value="raw"
                      selected={exportType === 'raw'}
                      onClick={() => setExportType('raw')}
                    />
                    <ExportOptionCard
                      icon="fa-file-lines"
                      color="bg-green-500"
                      label="Transcrits"
                      value="transcribed"
                      selected={exportType === 'transcribed'}
                      onClick={() => setExportType('transcribed')}
                    />
                    <ExportOptionCard
                      icon="fa-book"
                      color="bg-purple-500"
                      label="Projets de livre"
                      value="book"
                      selected={exportType === 'book'}
                      onClick={() => setExportType('book')}
                    />
                    <ExportOptionCard
                      icon="fa-eye"
                      color="bg-amber-500"
                      label="Relectures"
                      value="proofreading"
                      selected={exportType === 'proofreading1' || exportType === 'proofreading2'}
                      onClick={() => setExportType('proofreading1')}
                    />
                    <ExportOptionCard
                      icon="fa-layer-group"
                      color="bg-indigo-500"
                      label="Tout exporter"
                      value="all"
                      selected={exportType === 'all'}
                      onClick={() => setExportType('all')}
                      className="col-span-2"
                    />
                  </div>
                </div>

                {/* Format */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-3">
                    📄 Format d'export
                  </label>
                  <div className="flex gap-3">
                    <FormatOptionCard
                      icon="fa-file-code"
                      label="JSON"
                      value="json"
                      selected={exportFormat === 'json'}
                      onClick={() => setExportFormat('json')}
                    />
                    <FormatOptionCard
                      icon="fa-file-csv"
                      label="CSV"
                      value="csv"
                      selected={exportFormat === 'csv'}
                      onClick={() => setExportFormat('csv')}
                    />
                    <FormatOptionCard
                      icon="fa-file-pdf"
                      label="PDF"
                      value="pdf"
                      selected={exportFormat === 'pdf'}
                      onClick={() => setExportFormat('pdf')}
                    />
                  </div>
                </div>

                {/* Résumé */}
                <div className="bg-gray-50 dark:bg-gray-700/50 rounded-xl p-4">
                  <h4 className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                    📊 Résumé de l'export
                  </h4>
                  <div className="space-y-1 text-sm text-gray-600 dark:text-gray-400">
                    <p>• Type : <span className="font-medium text-purple-600 dark:text-purple-400">{getExportTypeLabel(exportType)}</span></p>
                    <p>• Format : <span className="font-medium text-purple-600 dark:text-purple-400">{exportFormat.toUpperCase()}</span></p>
                    <p>• Date : <span className="font-medium">{new Date().toLocaleDateString('fr-FR')}</span></p>
                  </div>
                </div>
              </div>

              {/* Pied */}
              <div className="px-6 py-4 bg-gray-50 dark:bg-gray-700/50 border-t border-gray-200 dark:border-gray-700 flex justify-end gap-3">
                <button
                  onClick={() => setExportModalOpen(false)}
                  className="px-5 py-2.5 text-sm font-medium bg-gray-200 dark:bg-gray-600 hover:bg-gray-300 dark:hover:bg-gray-500 text-gray-700 dark:text-gray-300 rounded-xl transition-all duration-200"
                >
                  Annuler
                </button>
                <button
                  onClick={handleExport}
                  disabled={isExporting}
                  className="px-5 py-2.5 text-sm font-medium bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 text-white rounded-xl transition-all duration-200 flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg hover:shadow-xl"
                >
                  {isExporting ? (
                    <>
                      <i className="fas fa-spinner animate-spin"></i>
                      Export en cours...
                    </>
                  ) : (
                    <>
                      <i className="fas fa-download"></i>
                      Exporter
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

// ✅ COMPOSANT CARTE OPTION D'EXPORT
const ExportOptionCard: React.FC<{
  icon: string;
  color: string;
  label: string;
  value: string;
  selected: boolean;
  onClick: () => void;
  className?: string;
}> = ({ icon, color, label, selected, onClick, className = '' }) => {
  return (
    <button
      onClick={onClick}
      className={`p-4 rounded-xl border-2 transition-all duration-200 flex items-center gap-3 ${
        selected
          ? 'border-purple-500 bg-purple-50 dark:bg-purple-900/20 shadow-lg'
          : 'border-gray-200 dark:border-gray-600 hover:border-purple-300 dark:hover:border-purple-500 hover:bg-gray-50 dark:hover:bg-gray-700/50'
      } ${className}`}
    >
      <div className={`w-10 h-10 ${color} rounded-lg flex items-center justify-center`}>
        <i className={`fas ${icon} text-white`}></i>
      </div>
      <span className="text-sm font-medium text-gray-700 dark:text-gray-300">{label}</span>
      {selected && (
        <i className="fas fa-check-circle text-purple-500 ml-auto"></i>
      )}
    </button>
  );
};

// ✅ COMPOSANT CARTE FORMAT
const FormatOptionCard: React.FC<{
  icon: string;
  label: string;
  value: string;
  selected: boolean;
  onClick: () => void;
}> = ({ icon, label, selected, onClick }) => {
  return (
    <button
      onClick={onClick}
      className={`flex-1 p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
        selected
          ? 'border-purple-500 bg-purple-50 dark:bg-purple-900/20 shadow-lg'
          : 'border-gray-200 dark:border-gray-600 hover:border-purple-300 dark:hover:border-purple-500'
      }`}
    >
      <i className={`fas ${icon} text-2xl ${selected ? 'text-purple-600' : 'text-gray-400'}`}></i>
      <span className="text-sm font-medium text-gray-700 dark:text-gray-300">{label}</span>
    </button>
  );
};

// ✅ FONCTION UTILITAIRE
const getExportTypeLabel = (type: string) => {
  switch (type) {
    case 'raw': return 'Fichiers bruts';
    case 'transcribed': return 'Transcrits';
    case 'book': return 'Projets de livre';
    case 'proofreading1': return 'Relecture 1';
    case 'proofreading2': return 'Relecture 2';
    case 'all': return 'Tous les fichiers';
    default: return 'Inconnu';
  }
};

export default MediaLibrary;
